import{_ as a,o as d,c as r,ag as e}from"./chunks/framework.Vng7Hdlh.js";const c=JSON.parse('{"title":"8. 会計・POSレジ","description":"","frontmatter":{},"headers":[],"relativePath":"internal/features/08-cashier.md","filePath":"internal/features/08-cashier.md"}'),l={name:"internal/features/08-cashier.md"};function i(h,t,o,n,s,p){return d(),r("div",null,[...t[0]||(t[0]=[e(`<h1 id="_8-会計・posレジ" tabindex="-1">8. 会計・POSレジ <a class="header-anchor" href="#_8-会計・posレジ" aria-label="Permalink to &quot;8. 会計・POSレジ&quot;">​</a></h1><p>POSレジ画面（<code>/kds/cashier.html</code>）は、テーブルの会計処理を行うための画面です。現金・クレジットカード・QRコード決済に対応し、割引・個別会計・レジ開閉・取引履歴・レシート発行の機能を備えています。</p><p>管理ダッシュボードのヘッダーにある「レジ」リンクをクリックすると、新しいタブで開きます。</p><h2 id="_8-1-画面構成" tabindex="-1">8.1 画面構成 <a class="header-anchor" href="#_8-1-画面構成" aria-label="Permalink to &quot;8.1 画面構成&quot;">​</a></h2><h3 id="ヘッダー" tabindex="-1">ヘッダー <a class="header-anchor" href="#ヘッダー" aria-label="Permalink to &quot;ヘッダー&quot;">​</a></h3><table tabindex="0"><thead><tr><th>要素</th><th>説明</th></tr></thead><tbody><tr><td>店舗名</td><td>現在の店舗名</td></tr><tr><td>スタッフ名</td><td>ログイン中のスタッフ名</td></tr><tr><td>デジタル時計</td><td>リアルタイムの時刻表示（HH:MM:SS）</td></tr><tr><td>📋 取引履歴ボタン</td><td>取引履歴パネルを開閉</td></tr><tr><td>💰 レジ開閉ボタン</td><td>レジ開け・閉め操作パネルを開閉</td></tr><tr><td>🔊 音声ボタン</td><td>効果音のON/OFF切替（設定はブラウザに保存）</td></tr></tbody></table><h3 id="左カラム-会計待ちテーブル一覧" tabindex="-1">左カラム：会計待ちテーブル一覧 <a class="header-anchor" href="#左カラム-会計待ちテーブル一覧" aria-label="Permalink to &quot;左カラム：会計待ちテーブル一覧&quot;">​</a></h3><p>会計を待っているテーブルとテイクアウト注文が一覧で表示されます。</p><p><strong>各カードの表示内容：</strong></p><table tabindex="0"><thead><tr><th>要素</th><th>説明</th></tr></thead><tbody><tr><td>テーブルコード</td><td>「5番」「A-1」など</td></tr><tr><td>テイクアウトバッジ</td><td>テイクアウト注文の場合「TO」バッジ</td></tr><tr><td>プラン情報</td><td>プラン/コース適用時：「コース ¥3,500 × 4名 = ¥14,000」</td></tr><tr><td>注文・品目数</td><td>「2注文 / 5品」</td></tr><tr><td>合計金額</td><td>注文合計（税込）</td></tr><tr><td>「会計」ボタン</td><td>このテーブルの会計を開始</td></tr></tbody></table><p><strong>合流会計ボタン：</strong> 左カラム上部に「合流会計」トグルボタンがあります。ONにすると複数テーブルの注文をまとめて1回の会計で処理できます。</p><p>会計待ちがない場合は「会計待ちの注文はありません」と表示されます。</p><h3 id="右カラム-posレジ" tabindex="-1">右カラム：POSレジ <a class="header-anchor" href="#右カラム-posレジ" aria-label="Permalink to &quot;右カラム：POSレジ&quot;">​</a></h3><p>テーブルを選択すると、右カラムに注文内容と決済操作が表示されます。</p><hr><h2 id="_8-2-会計の流れ" tabindex="-1">8.2 会計の流れ <a class="header-anchor" href="#_8-2-会計の流れ" aria-label="Permalink to &quot;8.2 会計の流れ&quot;">​</a></h2><h3 id="ステップ1-テーブルを選択する" tabindex="-1">ステップ1：テーブルを選択する <a class="header-anchor" href="#ステップ1-テーブルを選択する" aria-label="Permalink to &quot;ステップ1：テーブルを選択する&quot;">​</a></h3><ol><li>左カラムの会計待ちテーブル一覧から、会計するテーブルの「会計」ボタンをクリックします</li><li>右カラムにそのテーブルの注文内容が表示されます</li></ol><h3 id="ステップ2-注文内容を確認する" tabindex="-1">ステップ2：注文内容を確認する <a class="header-anchor" href="#ステップ2-注文内容を確認する" aria-label="Permalink to &quot;ステップ2：注文内容を確認する&quot;">​</a></h3><p>右カラムに表示される注文品目を確認します。</p><p><strong>品目の表示形式：</strong></p><table tabindex="0"><thead><tr><th>要素</th><th>説明</th></tr></thead><tbody><tr><td>チェックボックス</td><td>個別会計用（後述）</td></tr><tr><td>テーブル名</td><td>「[テーブル5]」形式</td></tr><tr><td>品名</td><td>メニュー名</td></tr><tr><td>軽減税率ラベル</td><td>テイクアウト品目に「軽減」ラベル（8%対象）</td></tr><tr><td>オプション</td><td>選択されたオプション（小文字）</td></tr><tr><td>数量</td><td>「×2」形式</td></tr><tr><td>価格</td><td>品目の合計金額</td></tr><tr><td>支払済み</td><td>一部支払い済みの品目は「支払済」表示（グレー）</td></tr></tbody></table><h3 id="ステップ3-割引を適用する-必要な場合" tabindex="-1">ステップ3：割引を適用する（必要な場合） <a class="header-anchor" href="#ステップ3-割引を適用する-必要な場合" aria-label="Permalink to &quot;ステップ3：割引を適用する（必要な場合）&quot;">​</a></h3><p>割引が必要な場合は、決済前に割引を設定します。</p><p><strong>割引の種類：</strong></p><table tabindex="0"><thead><tr><th>タイプ</th><th>ラジオボタン</th><th>入力例</th><th>説明</th></tr></thead><tbody><tr><td>金額割引</td><td>「金額」</td><td>500</td><td>固定金額（円）を割引</td></tr><tr><td>パーセント割引</td><td>「%」</td><td>10</td><td>合計の○%を割引</td></tr></tbody></table><p><strong>割引の操作：</strong></p><ol><li>割引タイプ（金額 or %）を選択します</li><li>値を入力します</li><li>「適用」ボタンをクリックします</li><li>合計金額の下に「割引 -¥500」のように表示されます</li><li>割引を取り消す場合は「取消」ボタンをクリックします</li></ol><h3 id="ステップ4-支払方法を選択する" tabindex="-1">ステップ4：支払方法を選択する <a class="header-anchor" href="#ステップ4-支払方法を選択する" aria-label="Permalink to &quot;ステップ4：支払方法を選択する&quot;">​</a></h3><p>3つの支払方法から選択します。</p><table tabindex="0"><thead><tr><th>方法</th><th>ボタン</th><th>動作</th></tr></thead><tbody><tr><td>現金</td><td>「現金」</td><td>テンキーで受取金額を入力</td></tr><tr><td>クレジットカード</td><td>「クレカ」</td><td>金額が自動入力される</td></tr><tr><td>QRコード</td><td>「QR」</td><td>金額が自動入力される</td></tr></tbody></table><h3 id="ステップ5-金額を入力する-現金の場合" tabindex="-1">ステップ5：金額を入力する（現金の場合） <a class="header-anchor" href="#ステップ5-金額を入力する-現金の場合" aria-label="Permalink to &quot;ステップ5：金額を入力する（現金の場合）&quot;">​</a></h3><p>現金を選択した場合、テンキーとクイック金額ボタンで受取金額を入力します。</p><p><strong>テンキー配置：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> 7   8   9</span></span>
<span class="line"><span> 4   5   6</span></span>
<span class="line"><span> 1   2   3</span></span>
<span class="line"><span>00   0   C</span></span></code></pre></div><ul><li><strong>C</strong>：入力をクリア</li><li>最大7桁まで入力可能</li></ul><p><strong>クイック金額ボタン：</strong></p><table tabindex="0"><thead><tr><th>ボタン</th><th>動作</th></tr></thead><tbody><tr><td>¥1,000</td><td>受取金額に1,000円を設定</td></tr><tr><td>¥5,000</td><td>受取金額に5,000円を設定</td></tr><tr><td>¥10,000</td><td>受取金額に10,000円を設定</td></tr><tr><td>ぴったり</td><td>合計金額と同額を自動入力</td></tr></tbody></table><p><strong>おつりの自動計算：</strong> 受取金額を入力すると、おつりが自動計算されて表示されます。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>受取金額：¥5,000</span></span>
<span class="line"><span>おつり　：¥1,360</span></span></code></pre></div><h3 id="ステップ6-会計を確定する" tabindex="-1">ステップ6：会計を確定する <a class="header-anchor" href="#ステップ6-会計を確定する" aria-label="Permalink to &quot;ステップ6：会計を確定する&quot;">​</a></h3><ol><li>「会計する」ボタンをクリックします</li><li>会計処理が実行されます</li><li>レシートプレビューモーダルが表示されます</li><li>注文ステータスが「paid」に更新されます</li><li>テーブルセッションが終了します</li><li>左カラムからそのテーブルが消えます</li></ol><p><strong>会計処理中：</strong> 二重送信防止のため、「会計する」ボタンは処理中に無効化されます。</p><hr><h2 id="_8-3-税金の計算" tabindex="-1">8.3 税金の計算 <a class="header-anchor" href="#_8-3-税金の計算" aria-label="Permalink to &quot;8.3 税金の計算&quot;">​</a></h2><p>POSLAは日本の消費税制度に対応し、品目ごとに税率を分けて計算します。</p><h3 id="税率の区分" tabindex="-1">税率の区分 <a class="header-anchor" href="#税率の区分" aria-label="Permalink to &quot;税率の区分&quot;">​</a></h3><table tabindex="0"><thead><tr><th>税率</th><th>対象</th><th>条件</th></tr></thead><tbody><tr><td>10%（標準税率）</td><td>店内飲食</td><td>デフォルト</td></tr><tr><td>8%（軽減税率）</td><td>テイクアウト</td><td>テイクアウト注文の場合</td></tr><tr><td>品目別税率</td><td>個別設定</td><td>品目に<code>taxRate</code>が設定されている場合</td></tr></tbody></table><h3 id="税額の表示" tabindex="-1">税額の表示 <a class="header-anchor" href="#税額の表示" aria-label="Permalink to &quot;税額の表示&quot;">​</a></h3><p>会計画面では税率区分ごとに内訳が表示されます。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>10%対象  ¥1,100 （税 ¥100）</span></span>
<span class="line"><span> 8%対象    ¥540 （税  ¥40）</span></span>
<span class="line"><span>─────────────────────────</span></span>
<span class="line"><span>合計      ¥1,640</span></span></code></pre></div><p><strong>計算方法（税込価格からの逆算）：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>税抜額 = 税込価格 ÷ (1 + 税率)  ※小数点以下切り捨て</span></span>
<span class="line"><span>税額 = 税込価格 − 税抜額</span></span></code></pre></div><hr><h2 id="_8-4-個別会計-割り勘" tabindex="-1">8.4 個別会計（割り勘） <a class="header-anchor" href="#_8-4-個別会計-割り勘" aria-label="Permalink to &quot;8.4 個別会計（割り勘）&quot;">​</a></h2><p>1つのテーブルの注文を品目単位で分けて、複数回に分けて会計できます。</p><h3 id="個別会計の操作" tabindex="-1">個別会計の操作 <a class="header-anchor" href="#個別会計の操作" aria-label="Permalink to &quot;個別会計の操作&quot;">​</a></h3><ol><li>テーブルの「会計」ボタンをクリックして注文を表示します</li><li>品目リストのチェックボックスで、今回支払う品目を選択します <ul><li>「全選択」：全品目を選択</li><li>「全解除」：全品目の選択を解除</li><li>個別チェックボックス：品目ごとに選択/解除</li></ul></li><li>一部のみ選択すると「個別会計」バッジが表示されます</li><li>選択した品目の合計が再計算されます</li><li>「個別会計する」ボタンで選択品目のみを会計します</li></ol><p><strong>個別会計後の状態：</strong></p><ul><li>支払い済みの品目は「支払済」表示（グレー）になり、チェックボックスがロックされます</li><li>残りの品目は次の会計を待ちます</li><li>全品目が支払い済みになるとテーブルセッションが終了します</li></ul><hr><h2 id="_8-5-合流会計" tabindex="-1">8.5 合流会計 <a class="header-anchor" href="#_8-5-合流会計" aria-label="Permalink to &quot;8.5 合流会計&quot;">​</a></h2><p>複数テーブルの注文をまとめて1回の会計で処理します。</p><ol><li>左カラム上部の「合流会計」ボタンをONにします</li><li>複数のテーブルを選択できるようになります</li><li>選択したテーブルの全注文が右カラムにまとめて表示されます</li><li>通常どおり会計処理を行います</li></ol><hr><h2 id="_8-6-レジ開閉操作" tabindex="-1">8.6 レジ開閉操作 <a class="header-anchor" href="#_8-6-レジ開閉操作" aria-label="Permalink to &quot;8.6 レジ開閉操作&quot;">​</a></h2><p>POSレジでは、営業開始時の「レジ開け」と営業終了時の「レジ閉め」を行います。</p><h3 id="レジ開け" tabindex="-1">レジ開け <a class="header-anchor" href="#レジ開け" aria-label="Permalink to &quot;レジ開け&quot;">​</a></h3><ol><li>ヘッダーの「💰 レジ開閉」ボタンをクリックしてパネルを開きます</li><li>「レジ開け」セクションで初期金額（つり銭準備金）を入力します</li><li>実行するとキャッシュログに記録されます</li></ol><table tabindex="0"><thead><tr><th>記録データ</th><th>値</th></tr></thead><tbody><tr><td>タイプ</td><td>open</td></tr><tr><td>金額</td><td>入力した金額</td></tr><tr><td>メモ</td><td>「レジ開け」</td></tr></tbody></table><h3 id="入金・出金" tabindex="-1">入金・出金 <a class="header-anchor" href="#入金・出金" aria-label="Permalink to &quot;入金・出金&quot;">​</a></h3><p>営業中に現金の入出金が発生した場合に記録します。</p><p><strong>入金（Cash In）：</strong></p><table tabindex="0"><thead><tr><th>フィールド</th><th>説明</th></tr></thead><tbody><tr><td>金額</td><td>入金額</td></tr><tr><td>メモ</td><td>入金理由（任意）</td></tr></tbody></table><p><strong>出金（Cash Out）：</strong></p><table tabindex="0"><thead><tr><th>フィールド</th><th>説明</th></tr></thead><tbody><tr><td>金額</td><td>出金額</td></tr><tr><td>メモ</td><td>出金理由（任意）</td></tr></tbody></table><h3 id="レジ閉め" tabindex="-1">レジ閉め <a class="header-anchor" href="#レジ閉め" aria-label="Permalink to &quot;レジ閉め&quot;">​</a></h3><ol><li>「レジ閉め」セクションで実際の現金残高を入力します</li><li>実行すると以下が表示されます</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td>実際</td><td>入力した現金残高</td></tr><tr><td>予想</td><td>システム計算の期待残高（開始金額 + 現金売上 + 入金 − 出金）</td></tr><tr><td>差額</td><td>実際 − 予想（過不足）</td></tr></tbody></table><ol start="3"><li>差額が記録され、レジ操作が無効化されます（営業終了）</li></ol><table tabindex="0"><thead><tr><th>記録データ</th><th>値</th></tr></thead><tbody><tr><td>タイプ</td><td>close</td></tr><tr><td>金額</td><td>入力した金額</td></tr><tr><td>メモ</td><td>「レジ閉め（差額: ±XXX）」</td></tr></tbody></table><hr><h2 id="_8-7-取引履歴-ジャーナル" tabindex="-1">8.7 取引履歴（ジャーナル） <a class="header-anchor" href="#_8-7-取引履歴-ジャーナル" aria-label="Permalink to &quot;8.7 取引履歴（ジャーナル）&quot;">​</a></h2><h3 id="パネルの開閉" tabindex="-1">パネルの開閉 <a class="header-anchor" href="#パネルの開閉" aria-label="Permalink to &quot;パネルの開閉&quot;">​</a></h3><ul><li>ヘッダーの「📋 取引履歴」ボタンをクリック</li><li>またはキーボードの <strong>J</strong> キーを押す</li></ul><h3 id="表示内容" tabindex="-1">表示内容 <a class="header-anchor" href="#表示内容" aria-label="Permalink to &quot;表示内容&quot;">​</a></h3><p>当日の全取引が一覧で表示されます。</p><table tabindex="0"><thead><tr><th>要素</th><th>説明</th></tr></thead><tbody><tr><td>タイムスタンプ</td><td>決済日時</td></tr><tr><td>決済ID</td><td>取引の一意識別子</td></tr><tr><td>テーブル/顧客名</td><td>対象テーブルまたはテイクアウト顧客名</td></tr><tr><td>品目サマリー</td><td>購入品目の概要</td></tr><tr><td>支払方法</td><td>現金/クレカ/QR</td></tr><tr><td>合計金額</td><td>決済金額</td></tr><tr><td>スタッフ名</td><td>会計を処理したスタッフ名</td></tr></tbody></table><hr><h2 id="_8-8-レシート" tabindex="-1">8.8 レシート <a class="header-anchor" href="#_8-8-レシート" aria-label="Permalink to &quot;8.8 レシート&quot;">​</a></h2><h3 id="レシートプレビュー" tabindex="-1">レシートプレビュー <a class="header-anchor" href="#レシートプレビュー" aria-label="Permalink to &quot;レシートプレビュー&quot;">​</a></h3><p>会計完了後にレシートプレビューモーダルが表示されます。キーボードの <strong>R</strong> キーでも表示できます。</p><p><strong>レシートの内容：</strong></p><table tabindex="0"><thead><tr><th>セクション</th><th>内容</th></tr></thead><tbody><tr><td>決済完了ステータス</td><td>—</td></tr><tr><td>テーブルコード</td><td>—</td></tr><tr><td>品目内訳（10%対象）</td><td>標準税率品目の一覧</td></tr><tr><td>品目内訳（8%対象）</td><td>軽減税率品目の一覧</td></tr><tr><td>合計金額</td><td>—</td></tr><tr><td>受取金額</td><td>現金の場合のみ</td></tr><tr><td>おつり</td><td>現金の場合のみ</td></tr><tr><td>支払方法</td><td>—</td></tr></tbody></table><h3 id="レシート印刷" tabindex="-1">レシート印刷 <a class="header-anchor" href="#レシート印刷" aria-label="Permalink to &quot;レシート印刷&quot;">​</a></h3><ol><li>レシートプレビューモーダルの「レシート印刷」ボタンをクリックします</li><li>ブラウザの印刷ダイアログが開きます（<code>window.print()</code>）</li><li>印刷用のCSSが適用されます</li></ol><div class="tip custom-block"><p class="custom-block-title">レシート設定</p><p>レシートの表示内容は管理ダッシュボードの「店舗設定」→「領収書設定」で設定できます。</p></div><hr><h2 id="_8-9-stripe決済端末連携" tabindex="-1">8.9 Stripe決済端末連携 <a class="header-anchor" href="#_8-9-stripe決済端末連携" aria-label="Permalink to &quot;8.9 Stripe決済端末連携&quot;">​</a></h2><p>proプラン以上で、Stripe Connectアカウントが設定されている場合、カードリーダー（Stripe Terminal）での決済に対応します。</p><h3 id="接続状態" tabindex="-1">接続状態 <a class="header-anchor" href="#接続状態" aria-label="Permalink to &quot;接続状態&quot;">​</a></h3><ul><li>ヘッダーにカードリーダーの接続状態が表示されます（緑色/赤色のドット）</li><li>「再検出」ボタンで再接続を試みます</li><li>Stripe Terminalが利用できない場合はステータス表示が自動的に非表示になります</li></ul><h3 id="カード決済の流れ" tabindex="-1">カード決済の流れ <a class="header-anchor" href="#カード決済の流れ" aria-label="Permalink to &quot;カード決済の流れ&quot;">​</a></h3><ol><li>支払方法で「クレカ」を選択します</li><li>「会計する」ボタンをクリックします</li><li>UIがロックされ、オーバーレイが表示されます <ul><li>「カードリーダーで決済準備中...」</li><li>「カードをリーダーにかざしてください」</li><li>キャンセルボタン</li></ul></li><li>お客さんがカードをリーダーにかざします</li><li>決済が完了するとレシートが表示されます</li></ol><p><strong>内部処理の流れ：</strong></p><ol><li>Stripe ConnectのPaymentIntentを作成</li><li>Stripe Terminalでカード情報を収集</li><li>決済を処理</li><li>POSLAに決済結果を記録</li></ol><hr><h2 id="_8-10-キーボードショートカット" tabindex="-1">8.10 キーボードショートカット <a class="header-anchor" href="#_8-10-キーボードショートカット" aria-label="Permalink to &quot;8.10 キーボードショートカット&quot;">​</a></h2><p>レジ画面では以下のキーボードショートカットが利用できます。</p><table tabindex="0"><thead><tr><th>キー</th><th>動作</th></tr></thead><tbody><tr><td>0〜9</td><td>受取金額に数字を追加（現金選択時）</td></tr><tr><td>Backspace</td><td>受取金額の最後の桁を削除</td></tr><tr><td>Escape</td><td>金額クリア / モーダル閉じ / パネル閉じ</td></tr><tr><td>Enter</td><td>会計を確定</td></tr><tr><td>F1</td><td>支払方法を「現金」に切替</td></tr><tr><td>F2</td><td>支払方法を「クレカ」に切替</td></tr><tr><td>F3</td><td>支払方法を「QR」に切替</td></tr><tr><td>J</td><td>取引履歴パネルを開閉</td></tr><tr><td>R</td><td>レシートプレビューを表示</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">キーボードショートカットの活用</p><p>PC接続のレジ端末では、キーボードショートカットを活用することで会計処理を高速化できます。テンキーで金額入力 → Enterで確定、という流れがスムーズです。</p></div>`,111)])])}const u=a(l,[["render",i]]);export{c as __pageData,u as default};
